Here is the commit message:
avformat/mov: Fix potential integer overflow in mov_read_keys

Actual allocation size is computed as (count + 1)*sizeof(meta_keys), so
we need to check that (count + 1) won't cause overflow.

Signed-off-by: Michael Niedermayer <michael@niedermayer.cc>

Here is the root cause:
The bug arises from a potential integer overflow when calculating the allocation size for `meta_keys`. The original check did not account for the additional `1` in the allocation formula `(count + 1) * sizeof(meta_keys)`, which could lead to an overflow if `count` is large enough, resulting in incorrect memory allocation and potential crashes or undefined behavior.

Here is the patch:

 static int mov_read_keys(MOVContext *c, AVIOContext *pb, MOVAtom atom)
 {
     uint32_t count;
     uint32_t i;

     if (atom.size < 8)
         return 0;

     avio_skip(pb, 4);
     count = avio_rb32(pb);
-    if (count > UINT_MAX / sizeof(*c->meta_keys)) {
+    if (count > UINT_MAX / sizeof(*c->meta_keys) - 1) {
         av_log(c->fc, AV_LOG_ERROR,
                "The 'keys' atom with the invalid key count: %d\n", count);
         return AVERROR_INVALIDDATA;
     }

     c->meta_keys_count = count + 1;
     c->meta_keys = av_mallocz(c->meta_keys_count * sizeof(*c->meta_keys));
     if (!c->meta_keys)
         return AVERROR(ENOMEM);

     for (i = 1; i <= count; ++i) {
         uint32_t key_size = avio_rb32(pb);
         uint32_t type = avio_rl32(pb);
         if (key_size < 8) {
             av_log(c->fc, AV_LOG_ERROR,
                    "The key# %d in meta has invalid size: %d\n", i, key_size);
             return AVERROR_INVALIDDATA;
         }
         key_size -= 8;
         if (type != MKTAG('m','d','t','a')) {
             avio_skip(pb, key_size);
         }
         c->meta_keys[i] = av_mallocz(key_size + 1);
         if (!c->meta_keys[i])
             return AVERROR(ENOMEM);
         avio_read(pb, c->meta_keys[i], key_size);
     }

     return 0;
 }



